{
  "code": "module.exports = async ({ page }) => {
  // 1. Navigate to your Splunk Dashboard
  await page.goto('http://192.168.4.27:8000/en-US/app/search/homelab_network_overview?tab=layout_1&form.global_time.earliest=0&form.global_time.latest=now', { waitUntil: 'networkidle2' });

  // 2. Wait for the login form and enter credentials
  await page.waitForSelector('input[name="username"]', { timeout: 5000 }).catch(() => {});

  // Check if we are actually on the login page
  const isLoginPage = await page.$('input[name="username"]');
  if (isLoginPage) {
    await page.type('input[name="username"]', 'Admin');
    await page.type('input[name="password"]', 'ChickenBisque5*');

    // Click the submit button and wait for the dashboard to load
    await Promise.all([
      page.click('.btn-primary, input[type="submit"]'),
      page.waitForNavigation({ waitUntil: 'networkidle2' })
    ]);
  }

  // 3. Set standard desktop viewport size
  await page.setViewport({ width: 500, height: 1080 });

  // 4. Give Splunk charts an extra 5 seconds to finish rendering queries
  await new Promise(r => setTimeout(r, 5000));

  // 5. Take the screenshot and return it
  const screenshot = await page.screenshot({type: 'png', clip: {x:100,y: 170,width:850 ,height: 350}});
  return {
    data: screenshot.toString('base64'),
    type: 'image/png'
  };
};"}

